code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = pow (0.9, 30/fps);;
dec_slow = pow (0.99, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (.2+avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %8;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = bass + mid + treb;;
k1 =  is_beat*((index) == (0));;
p1 =  k1*(p1+1) + (1-k1)*p1;;
p2 = dec_slow * p2+ (1-dec_slow)*p1;;
rott = p2 * 3.1416/4;;
q27 = index + 1;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
zoom = 1.0;;
rot = -0.00 * index;;
q32 = pow(0.996, 30/fps); //fade;
q5 = (sin(time/11)+1)/5;;
movez = movez + .06/fps*(1.1+q1);;
q6 = movez;;
q7 = .005*sin(time/15);
